#include <vector>
#include <algorithm>

using namespace std;

long long solve(vector<long long> nums) {
    int n = nums.size();
    long long count = 0;

    for (int l = 0; l < n; ++l) {
        int max_mid = 0;
        for (int r = l + 2; r < n; ++r) {
            if (r == l + 2) {
                max_mid = nums[l + 1];
            } else {
                max_mid = max(max_mid, nums[r - 1]);
            }
            if (min(nums[l], nums[r]) > max_mid) {
                count++;
            } else {
                // Once the condition fails, larger r won't satisfy either
                break;
            }
        }
    }

    return count;
}
